function WaitlistForm({ dark = false, id }) {
  const [email, setEmail] = useState("");
  const [submitted, setSubmitted] = useState(false);

  function handleSubmit(e) {
    e.preventDefault();
    if (!email.includes("@")) return;
    setSubmitted(true);
  }

  if (submitted) {
    return (
      <div
        className="flex items-center gap-2 rounded-full px-4 py-3 text-sm font-medium"
        style={{ background: dark ? "rgba(159,225,203,0.15)" : "rgba(255,255,255,0.9)", color: dark ? TOKENS.prayer : TOKENS.prayerDeep }}
      >
        <Check size={16} />
        You're on the list. We'll be in touch.
      </div>
    );
  }

  return (
    <form onSubmit={handleSubmit} className="flex w-full max-w-md flex-col gap-2 sm:flex-row" id={id}>
      <label htmlFor={`${id}-email`} className="sr-only">Church or work email</label>
      <input
        id={`${id}-email`}
        type="email"
        required
        placeholder="you@yourchurch.org"
        value={email}
        onChange={(e) => setEmail(e.target.value)}
        className="w-full rounded-full border px-4 py-3 text-sm outline-none transition focus-visible:ring-2"
        style={{
          background: dark ? "rgba(255,255,255,0.1)" : "rgba(255,255,255,0.95)",
          borderColor: dark ? "rgba(255,255,255,0.22)" : "rgba(255,255,255,0.5)",
          color: dark ? "#fff" : TOKENS.ink,
        }}
      />
      <button
        type="submit"
        className="flex shrink-0 items-center justify-center gap-1.5 rounded-full px-5 py-3 text-sm font-semibold transition hover:opacity-90"
        style={{ background: dark ? TOKENS.brand : "#fff", color: dark ? "#fff" : TOKENS.brand }}
      >
        Join waitlist
        <ArrowRight size={15} />
      </button>
    </form>
  );
}

